import "fmt"

// minMax returns the smallest and largest of nums (0, 0 if none are given).
func minMax(nums ...int) (lo, hi int) {
	if len(nums) == 0 {
		return 0, 0
	}
	lo, hi = nums[0], nums[0]
	for _, n := range nums[1:] {
		if n < lo {
			lo = n
		}
		if n > hi {
			hi = n
		}
	}
	return lo, hi
}

func main() {
	lo, hi := minMax(3, 7, 1, 9, 4)
	fmt.Printf("min=%d max=%d\n", lo, hi)
}
