// slowOp simulates work that takes 200ms and respects cancellation.
func slowOp(ctx context.Context) (string, error) {
	select {
	case <-time.After(200 * time.Millisecond):
		return "done", nil
	case <-ctx.Done():
		return "", ctx.Err()
	}
}

