func newSafeMap() *safeMap { return &safeMap{m: make(map[string]int)} }

func (s *safeMap) inc(key string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.m[key]++
}

func (s *safeMap) get(key string) int {
	s.mu.Lock()
	defer s.mu.Unlock()
	return s.m[key]
}

func main() {
	sm := newSafeMap()
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			sm.inc("hits")
		}()
	}
	wg.Wait()
	fmt.Println("hits:", sm.get("hits"))
}
