	s := &server{host: "localhost", port: 8080} // defaults
	for _, opt := range opts {
		opt(s)
	}
	return s
}

func main() {
	s := newServer(WithHost("example.com"), WithPort(443), WithTLS())
	fmt.Printf("%+v\n", *s)
}
